// Find pair with target sum in sorted array
int two_sum_sorted(int *arr, int n, int target, int *i, int *j) {
    int lo = 0, hi = n - 1;
    while (lo < hi) {
        int sum = arr[lo] + arr[hi];
        if (sum == target) { *i = lo; *j = hi; return 1; }
        if (sum < target) lo++;
        else hi--;
    }
    return 0;
}

