// Maximum sum subarray of size k
int max_sum_k(int *arr, int n, int k) {
    int window_sum = 0;
    for (int i = 0; i < k; i++)
        window_sum += arr[i];
    int max_sum = window_sum;
    for (int i = k; i < n; i++) {
        window_sum += arr[i] - arr[i - k];
        if (window_sum > max_sum)
            max_sum = window_sum;
    }
    return max_sum;
}

